@import '../../utils/control-inactive.css';

.checkbox {
  display: flex;
  align-items: center;
  gap: var(--dimension-space-050);
  padding: var(--dimension-space-075);
  height: var(--dimension-size-400);
  box-sizing: border-box;
  cursor: pointer;
  user-select: none;
  border-radius: var(--dimension-radius-075);
  transition: background-color var(--effect-motion-short-2);
}

.checkbox:hover {
  background-color: var(--color-interaction-hover);
}

.checkbox:active {
  background-color: var(--color-interaction-pressed);
}

/* Inactive: `.ds-control-inactive` (25% opacity). */

/* ── Default box indicator ───────────────────────────────────────────────── */

.box {
  width: var(--dimension-iconography-md);
  height: var(--dimension-iconography-md);
  flex-shrink: 0;
  border: var(--dimension-stroke-width-018) solid var(--color-foreground-secondary);
  border-radius: var(--dimension-radius-050);
  display: flex;
  align-items: center;
  justify-content: center;
  box-sizing: border-box;
  transition: all var(--effect-motion-short-2);
}

.box--marked {
  background-color: var(--color-foreground-primary);
  border-color: var(--color-foreground-primary);
}

.checkmark {
  color: var(--color-foreground-on-bold-background-primary);
  font-size: var(--typography-fontsize-md);
  line-height: var(--typography-lineheight-md);
  font-weight: var(--typography-weight-bold);
}

/* ── Label ───────────────────────────────────────────────────────────────── */

.checkbox__label {
  flex: 1;
  min-width: 0;
}

import { AttachInternals, Component, Prop, State, Event, EventEmitter, Watch, h, Host } from '@stencil/core';

let idCounter = 0;

@Component({
  tag: 'ds-checkbox',
  styleUrl: 'Checkbox.css',
  scoped: true,
  formAssociated: true,
})
export class Checkbox {
  @AttachInternals() internals!: ElementInternals;
  private labelId = `ds-checkbox-label-${++idCounter}`;

  @Prop() label!: string;
  @Prop({ mutable: true }) checked: boolean = false;
  @Prop({ reflect: true }) name: string | undefined;
  @Prop() value: string = 'on';
  @Prop({ reflect: true }) disabled: boolean = false;
  @Prop({ reflect: true }) required: boolean = false;
  @Prop() requiredMessage: string = 'This field is required.';
  @Prop() indeterminate: boolean = false;
  @Prop() isInactive: boolean = false;

  @Event() dsChange!: EventEmitter<boolean>;

  private initialChecked = false;
  @State() private formDisabled = false;

  componentWillLoad() {
    this.initialChecked = this.checked;
    this.syncFormValue();
  }

  @Watch('checked')
  @Watch('value')
  @Watch('disabled')
  @Watch('isInactive')
  @Watch('required')
  syncFormValue() {
    const inactive = this.isInactive || this.disabled || this.formDisabled;
    this.internals.setFormValue(!inactive && this.checked ? this.value : null);
    const missing = this.required && !inactive && !this.checked;
    this.internals.setValidity(missing ? { valueMissing: true } : {}, missing ? this.requiredMessage : '');
  }

  formDisabledCallback(disabled: boolean) {
    this.formDisabled = disabled;
    this.syncFormValue();
  }

  formResetCallback() {
    this.checked = this.initialChecked;
  }

  private handleActivate = () => {
    if (this.isInactive || this.disabled || this.formDisabled) return;
    this.checked = !this.checked;
    this.dsChange.emit(this.checked);
  };

  private handleKeyDown = (e: KeyboardEvent) => {
    if (e.key === ' ' || e.key === 'Enter') {
      e.preventDefault();
      this.handleActivate();
    }
  };

  render() {
    const inactive = this.isInactive || this.disabled || this.formDisabled;
    const isMarked = this.checked || this.indeterminate;

    return (
      <Host
        role="checkbox"
        aria-checked={this.indeterminate ? 'mixed' : String(this.checked)}
        aria-disabled={inactive ? 'true' : undefined}
        aria-labelledby={this.labelId}
        tabIndex={inactive ? -1 : 0}
        class={{ checkbox: true, 'ds-control-inactive': inactive }}
        onClick={this.handleActivate}
        onKeyDown={this.handleKeyDown}
      >
        <span class={{ box: true, 'box--marked': isMarked }}>
          {isMarked && (
            <span class="checkmark" aria-hidden="true">
              {this.indeterminate ? '−' : '✓'}
            </span>
          )}
        </span>
        <ds-text class="checkbox__label" as="span" variant="text-body-medium" textId={this.labelId}>
          {this.label}
        </ds-text>
      </Host>
    );
  }
}
